// Command Nofrixion-cli is a CLI + REPL for the Nofrixion SDK,
// built on the AQL engine. Positional arguments are joined into a
// single AQL expression and evaluated; with no arguments, falls into
// a REPL. Generated by sdkgen go-cli target.
package main

import (
	"bufio"
	"fmt"
	"io"
	"os"
	"strings"

	eng "github.com/aql-lang/aql/eng/go"
	"github.com/aql-lang/aql/eng/go/parser"
	sdk "github.com/voxgig-sdk/nofrixion-sdk/go"
)

// prompt is the REPL prompt prefix (matches the SDK slug).
const prompt = "nofrixion"

// entitiesHelp is the space-separated entity list shown by :help.
const entitiesHelp = "account beneficiary cancel disable enable merchant metadata no_frixion_biz_biz_models_paging_merchant_direct_debit_mandate_page no_frixion_biz_biz_models_paging_payment_request_page no_frixion_biz_biz_models_paging_payout_page no_frixion_biz_biz_models_paging_payrun_page no_frixion_biz_biz_models_paging_rule_events_page no_frixion_biz_biz_models_paging_rules_page no_frixion_biz_biz_models_payments_card_payment no_frixion_biz_biz_models_payments_card_public_key no_frixion_money_moov_api_features_beneficiaries_beneficiaries no_frixion_money_moov_api_features_payment_requests_payment no_frixion_money_moov_api_features_permissions_roles_create no_frixion_money_moov_api_features_user_invites_create no_frixion_money_moov_models_authorisation_settings_merchant no_frixion_money_moov_models_batch_payout no_frixion_money_moov_models_beneficiary_group_page no_frixion_money_moov_models_beneficiary_page no_frixion_money_moov_models_card_customer_token no_frixion_money_moov_models_currency_currency_info no_frixion_money_moov_models_direct_debit_batch_submit no_frixion_money_moov_models_fx_rate no_frixion_money_moov_models_i_payment no_frixion_money_moov_models_mandates_mandate no_frixion_money_moov_models_merchant no_frixion_money_moov_models_merchant_page no_frixion_money_moov_models_merchant_pay_by_bank_setting no_frixion_money_moov_models_merchant_token no_frixion_money_moov_models_merchant_token_page no_frixion_money_moov_models_no_frixion_version no_frixion_money_moov_models_open_banking_account no_frixion_money_moov_models_open_banking_consent no_frixion_money_moov_models_open_banking_transaction no_frixion_money_moov_models_payment no_frixion_money_moov_models_payment_account_minimal_page no_frixion_money_moov_models_payment_account_page no_frixion_money_moov_models_payment_initiation no_frixion_money_moov_models_payment_request_event no_frixion_money_moov_models_payment_request_metric no_frixion_money_moov_models_payment_request_minimal no_frixion_money_moov_models_payment_request_result no_frixion_money_moov_models_payment_requests_merchant_payment no_frixion_money_moov_models_payment_requests_merchant_payment2 no_frixion_money_moov_models_payment_requests_merchant_payment3 no_frixion_money_moov_models_payment_requests_merchant_payment4 no_frixion_money_moov_models_payout_keyset_page no_frixion_money_moov_models_payout_metric no_frixion_money_moov_models_payouts_payouts_create no_frixion_money_moov_models_payrun no_frixion_money_moov_models_report_result no_frixion_money_moov_models_rule no_frixion_money_moov_models_transaction no_frixion_money_moov_models_transaction_page no_frixion_money_moov_models_user_invite no_frixion_money_moov_models_user_invite_page no_frixion_money_moov_models_user_page no_frixion_money_moov_models_webhook open_banking payeeverification payment_request payout payrun reject report rule send sendbeneficiary tag token transaction user user_invite virtual webhook whoami whoamitrustedapp"

func main() {
	os.Exit(run(os.Args[1:], os.Stdin, os.Stdout, os.Stderr))
}

func run(args []string, in io.Reader, out, errOut io.Writer) int {
	client := sdk.NewNofrixionSDK(nil)

	r, err := eng.NewRegistry()
	if err != nil {
		fmt.Fprintf(errOut, "registry: %v\n", err)
		return 1
	}
	registerSDKWords(r, client)
	if err := r.Err(); err != nil {
		fmt.Fprintf(errOut, "word registration: %v\n", err)
		return 1
	}
	r.SetParseFunc(parser.Parse)
	r.InitRootContext()
	r.MarkReady()

	if len(args) > 0 {
		return evalOnce(r, strings.Join(args, " "), out, errOut)
	}
	repl(r, in, out)
	return 0
}

func evalOnce(r *eng.Registry, src string, out, errOut io.Writer) int {
	values, err := parser.Parse(src)
	if err != nil {
		fmt.Fprintf(errOut, "parse: %v\n", err)
		return 1
	}
	result, err := eng.NewTop(r).Run(values)
	if err != nil {
		fmt.Fprintf(errOut, "error: %v\n", err)
		return 1
	}
	for _, v := range result {
		fmt.Fprintln(out, v.String())
	}
	return 0
}

func repl(r *eng.Registry, in io.Reader, out io.Writer) {
	scanner := bufio.NewScanner(in)
	scanner.Buffer(make([]byte, 0, 64*1024), 1024*1024)
	for {
		fmt.Fprintf(out, "%s> ", prompt)
		if !scanner.Scan() {
			fmt.Fprintln(out)
			return
		}
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		switch line {
		case ":quit", ":q", ":exit":
			return
		case ":help", ":h", ":?":
			fmt.Fprintln(out, "commands: list / load / update <query?> <entity>")
			fmt.Fprintln(out, "entities:", entitiesHelp)
			fmt.Fprintln(out, "meta:     :quit :help")
			continue
		}
		values, err := parser.Parse(line)
		if err != nil {
			fmt.Fprintf(out, "  parse error: %v\n", err)
			continue
		}
		result, err := eng.NewTop(r).Run(values)
		if err != nil {
			fmt.Fprintf(out, "  error: %v\n", err)
			continue
		}
		for _, v := range result {
			fmt.Fprintln(out, v.String())
		}
	}
}
